};

import { UserModel } from '../models/user.model';
import { redis } from '../infra/redis';

type UserDoc = { _id: string; email: string; displayName: string; role: string };

export const userRepo = {
  async findById(id: string): Promise<UserDoc | null> {
    const cached = await redis.get(`user:${id}`);
    if (cached) return JSON.parse(cached);
    const user = await UserModel.findById(id).lean();
    if (!user) return null;
    const slim: UserDoc = { _id: String(user._id), email: user.email, displayName: user.displayName, role: user.role };
    await redis.set(`user:${id}`, JSON.stringify(slim), { EX: 3600 });
    return slim;
  },
  async invalidate(id: string) {
    await redis.del(`user:${id}`);
    await redis.publish('user:invalidate', id);
  }
};

import { Request, Response, NextFunction } from 'express';
import { userRepo } from '../dal/user.repo';

declare global { namespace Express { interface Request { loaders?: { user: (id: string) => Promise<unknown> } } } }

export function requestLoader(req: Request, _res: Response, next: NextFunction) {
  const userCache = new Map<string, Promise<unknown>>();
  req.loaders = {
    user(id: string) {
      if (!userCache.has(id)) userCache.set(id, userRepo.findById(id));
      return userCache.get(id)!;
    }
  };
  next();
}

import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';
import { HttpError } from '../errors/http-error';

export async function requireAuth(req: Request, _res: Response, next: NextFunction) {
  try {
    const auth = req.headers.authorization;
    if (!auth?.startsWith('Bearer ')) throw new HttpError(401, 'UNAUTHENTICATED');
    const payload = jwt.verify(auth.slice(7), process.env.JWT_SECRET!) as { sub: string };
    const user = await req.loaders!.user(payload.sub) as { _id: string; role: string } | null;
    if (!user) throw new HttpError(401, 'UNAUTHENTICATED');
    req.user = { id: user._id, role: user.role };
    next();
  } catch (err) { next(err); }
}

import { Schema, model } from 'mongoose';
import { userRepo } from '../dal/user.repo';

const UserSchema = new Schema({
  email: { type: String, required: true },
  displayName: String,
  passwordHash: String,
  role: { type: String, default: 'user' }
}, { timestamps: true });

UserSchema.post('save', async function(doc) { await userRepo.invalidate(doc._id.toString()); });
UserSchema.post(['updateOne','findOneAndUpdate'] as any, async function(this: any) {
  const filter = this.getFilter();
  if (filter._id) await userRepo.invalidate(String(filter._id));
});

export const UserModel = model('User', UserSchema);

import { redis } from './redis';
import { userRepo } from '../dal/user.repo';

export function startCacheSubscriber() {
  const sub = redis.duplicate();
  sub.subscribe('user:invalidate', async (id) => {
    // local Redis cache is shared across instances; this would matter only if we had in-process caches
    void userRepo;
    void id;
  });
}

