import { Request, Response, NextFunction } from 'express';
import { DraftModel } from '../models/draft.model';
import { HttpError } from '../errors/http-error';
import { io } from '../infra/socketio';

export const saveDraft = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const userId = req.user!.id;
    const { postId } = req.params;
    const { body, expectedVersion } = req.body as { body: string; expectedVersion: number };
    const updated = await DraftModel.findOneAndUpdate(
      { postId, userId, version: expectedVersion },
      { $set: { body }, $inc: { version: 1 } },
      { new: true }
    );
    if (!updated) {
      const current = await DraftModel.findOne({ postId, userId }).lean();
      throw new HttpError(409, 'CONFLICT', { current });
    }
    io.of('/drafts').to(`user:${userId}`).except(req.headers['x-client-id'] as string).emit('draft:updated', { postId, body: updated.body, version: updated.version });
    res.json({ version: updated.version });
  } catch (err) { next(err); }
};

import { useEffect, useRef, useState } from 'react';
import { io } from 'socket.io-client';
import { fetchDraft, postDraft } from '../../api/posts';

export function useDraft(postId: string, token: string, clientId: string) {
  const [body, setBody] = useState('');
  const [version, setVersion] = useState(0);
  const [conflict, setConflict] = useState<{ serverBody: string; serverVersion: number } | null>(null);
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const inFlight = useRef(false);

  useEffect(() => { fetchDraft(postId).then(d => { setBody(d.body); setVersion(d.version); }); }, [postId]);

  useEffect(() => {
    const socket = io('/drafts', { auth: { token }, query: { clientId }, transports: ['websocket'] });
    socket.on('draft:updated', (u: { postId: string; body: string; version: number }) => {
      if (u.postId !== postId) return;
      if (u.version > version) { setBody(u.body); setVersion(u.version); }
    });
    return () => { socket.disconnect(); };
  }, [postId, token, clientId, version]);

  const onChange = (next: string) => {
    setBody(next);
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(async () => {
      if (inFlight.current) return;
      inFlight.current = true;
      try {
        const r = await postDraft(postId, { body: next, expectedVersion: version }, clientId);
        setVersion(r.version);
      } catch (err) {
        if ((err as { status?: number }).status === 409) {
          const detail = (err as { details?: { current?: { body: string; version: number } } }).details;
          if (detail?.current) setConflict({ serverBody: detail.current.body, serverVersion: detail.current.version });
        }
      } finally { inFlight.current = false; }
    }, 2000);
  };

  const resolveConflictKeepMine = async () => {
    if (!conflict) return;
    const r = await postDraft(postId, { body, expectedVersion: conflict.serverVersion }, clientId);
    setVersion(r.version); setConflict(null);
  };
  const resolveConflictAcceptTheirs = () => {
    if (!conflict) return;
    setBody(conflict.serverBody); setVersion(conflict.serverVersion); setConflict(null);
  };

  return { body, onChange, conflict, resolveConflictKeepMine, resolveConflictAcceptTheirs };
}

import { useDraft } from './useDraft';

export function Editor({ postId, token, clientId }: { postId: string; token: string; clientId: string }) {
  const { body, onChange, conflict, resolveConflictKeepMine, resolveConflictAcceptTheirs } = useDraft(postId, token, clientId);
  return (
    <div>
      <textarea className="w-full h-96 p-3 border" value={body} onChange={e => onChange(e.target.value)} />
      {conflict && (
        <div className="border-2 border-amber-500 p-3 mt-2">
          <div>Another device updated this draft. Choose which to keep:</div>
          <pre className="text-xs bg-gray-100 p-2 mt-1">{conflict.serverBody.slice(0, 200)}...</pre>
          <button onClick={resolveConflictKeepMine} className="px-3 py-1 bg-black text-white rounded mr-2">Keep my changes</button>
          <button onClick={resolveConflictAcceptTheirs} className="px-3 py-1 border rounded">Accept theirs</button>
        </div>
      )}
    </div>
  );
}

