import { redis } from '../infra/redis';
import crypto from 'node:crypto';

const KEY = 'leader:scheduler';
const LEASE_SECONDS = 15;
const RENEW_INTERVAL_MS = 5000;

export class LeaderElection {
  private id = crypto.randomUUID();
  private isLeader = false;
  private timer: ReturnType<typeof setInterval> | null = null;
  private listeners: Array<(leader: boolean) => void> = [];
  on(listener: (leader: boolean) => void) { this.listeners.push(listener); }
  private notify() { for (const l of this.listeners) l(this.isLeader); }
  async start() {
    const tick = async () => {
      if (this.isLeader) {
        const renewed = await redis.eval(
          "if redis.call('GET', KEYS[1]) == ARGV[1] then return redis.call('EXPIRE', KEYS[1], ARGV[2]) else return 0 end",
          { keys: [KEY], arguments: [this.id, String(LEASE_SECONDS)] }
        );
        if (renewed !== 1) { this.isLeader = false; this.notify(); }
      } else {
        const got = await redis.set(KEY, this.id, { NX: true, EX: LEASE_SECONDS });
        if (got === 'OK') { this.isLeader = true; this.notify(); }
      }
    };
    await tick();
    this.timer = setInterval(tick, RENEW_INTERVAL_MS);
  }
  async stop() {
    if (this.timer) clearInterval(this.timer);
    if (this.isLeader) {
      await redis.eval("if redis.call('GET', KEYS[1]) == ARGV[1] then return redis.call('DEL', KEYS[1]) else return 0 end", { keys: [KEY], arguments: [this.id] });
      this.isLeader = false;
    }
  }
}

import cronParser from 'cron-parser';
import { JobRunModel } from '../models/job-run.model';
import { logger } from '../infra/logger';

export type JobDef = { name: string; cron: string; handler: () => Promise<void>; maxConcurrent?: number };

export class Scheduler {
  private nextRun = new Map<string, Date>();
  private running = new Map<string, number>();
  private timer: ReturnType<typeof setInterval> | null = null;
  constructor(private jobs: JobDef[]) {
    for (const j of jobs) this.nextRun.set(j.name, cronParser.parseExpression(j.cron).next().toDate());
  }
  start() {
    this.timer = setInterval(() => this.tick(), 1000);
  }
  stop() { if (this.timer) clearInterval(this.timer); }
  private async tick() {
    const now = new Date();
    for (const job of this.jobs) {
      const due = this.nextRun.get(job.name)!;
      if (due > now) continue;
      this.nextRun.set(job.name, cronParser.parseExpression(job.cron).next().toDate());
      const inFlight = this.running.get(job.name) ?? 0;
      if (inFlight >= (job.maxConcurrent ?? 1)) { logger.warn({ job: job.name }, 'skipping run - max concurrent reached'); continue; }
      this.running.set(job.name, inFlight + 1);
      const run = await JobRunModel.create({ jobName: job.name, status: 'running', startedAt: now });
      job.handler()
        .then(async () => { run.status = 'success'; run.endedAt = new Date(); await run.save(); })
        .catch(async (err) => { run.status = 'failed'; run.error = String(err); run.endedAt = new Date(); await run.save(); logger.error({ job: job.name, err }, 'job failed'); })
        .finally(() => { this.running.set(job.name, (this.running.get(job.name) ?? 1) - 1); });
    }
  }
}

import { LeaderElection } from './leader';
import { Scheduler } from './scheduler';
import { generateDailyReport } from './daily-report';
import { cleanupTempFiles } from './cleanup';

const jobs = [
  { name: 'daily-report', cron: '0 1 * * *', handler: generateDailyReport, maxConcurrent: 1 },
  { name: 'cleanup-temp', cron: '0 * * * *', handler: cleanupTempFiles, maxConcurrent: 1 }
];

let scheduler: Scheduler | null = null;

export async function startJobs() {
  const leader = new LeaderElection();
  leader.on((isLeader) => {
    if (isLeader && !scheduler) { scheduler = new Scheduler(jobs); scheduler.start(); }
    else if (!isLeader && scheduler) { scheduler.stop(); scheduler = null; }
  });
  await leader.start();
}

import { useState } from 'react';

type Card = { id: string; title: string; listId: string };
type List = { id: string; title: string; cards: Card[] };

export function Board({ initial }: { initial: List[] }) {
  const [lists, setLists] = useState(initial);
  const renameCard = (cardId: string, title: string) => {
    setLists(prev => prev.map(l => ({ ...l, cards: l.cards.map(c => c.id === cardId ? { ...c, title } : c) })));
  };
  return <div>{lists.map(l => <div key={l.id}>{l.cards.map(c => <div key={c.id}>{c.title}</div>)}</div>)}</div>;
}

export type Card = { id: string; title: string; listId: string };
export type List = { id: string; title: string; cardIds: string[] };
export type BoardState = { cards: Map<string, Card>; lists: Map<string, List>; listOrder: string[] };

type Listener = () => void;
const listeners = new Set<Listener>();
let state: BoardState = { cards: new Map(), lists: new Map(), listOrder: [] };

function emit() { for (const l of listeners) l(); }

export const boardStore = {
  getState: () => state,
  subscribe: (l: Listener) => { listeners.add(l); return () => { listeners.delete(l); }; },
  load(lists: { id: string; title: string; cards: Card[] }[]) {
    const cards = new Map<string, Card>();
    const listsMap = new Map<string, List>();
    const order: string[] = [];
    for (const l of lists) {
      const cardIds: string[] = [];
      for (const c of l.cards) { cards.set(c.id, c); cardIds.push(c.id); }
      listsMap.set(l.id, { id: l.id, title: l.title, cardIds });
      order.push(l.id);
    }
    state = { cards, lists: listsMap, listOrder: order };
    emit();
  },
  renameCard(cardId: string, title: string) {
    const c = state.cards.get(cardId);
    if (!c) return;
    const next = new Map(state.cards);
    next.set(cardId, { ...c, title });
    state = { ...state, cards: next };
    emit();
  },
  moveCard(cardId: string, toListId: string, toIndex: number) {
    const card = state.cards.get(cardId);
    if (!card) return;
    const fromList = state.lists.get(card.listId);
    const toList = state.lists.get(toListId);
    if (!fromList || !toList) return;
    const newLists = new Map(state.lists);
    newLists.set(fromList.id, { ...fromList, cardIds: fromList.cardIds.filter(id => id !== cardId) });
    const toCardIds = newLists.get(toList.id)!.cardIds.slice();
    toCardIds.splice(toIndex, 0, cardId);
    newLists.set(toList.id, { ...toList, cardIds: toCardIds });
    const newCards = new Map(state.cards);
    newCards.set(cardId, { ...card, listId: toListId });
    state = { ...state, lists: newLists, cards: newCards };
    emit();
  }
};

