import { OrderModel } from '../models/order.model';
import { ExportJobModel } from '../models/export-job.model';
import { format } from '@fast-csv/format';
import { S3Client, PutObjectCommand } from '@aws-sdk/client-s3';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';
import { Upload } from '@aws-sdk/lib-storage';
import { GetObjectCommand } from '@aws-sdk/client-s3';

const s3 = new S3Client({ region: process.env.AWS_REGION! });
const BUCKET = process.env.EXPORT_BUCKET!;

export async function processExport(jobId: string) {
  const job = await ExportJobModel.findById(jobId);
  if (!job) return;
  job.status = 'running'; job.startedAt = new Date(); await job.save();
  try {
    const csv = format({ headers: true });
    const key = `exports/${job._id}.csv`;
    const upload = new Upload({ client: s3, params: { Bucket: BUCKET, Key: key, Body: csv, ContentType: 'text/csv' } });
    const cursor = OrderModel.find(job.filters as object).cursor();
    let count = 0;
    for await (const o of cursor) {
      csv.write({ id: String(o._id), total: o.total, status: o.status, createdAt: o.createdAt.toISOString() });
      count++;
      if (count % 5000 === 0) { job.processedRows = count; await job.save(); }
    }
    csv.end();
    await upload.done();
    const url = await getSignedUrl(s3, new GetObjectCommand({ Bucket: BUCKET, Key: key }), { expiresIn: 3600 });
    job.status = 'done'; job.downloadUrl = url; job.processedRows = count; job.completedAt = new Date(); await job.save();
  } catch (err) {
    job.status = 'failed'; job.error = (err as Error).message; await job.save();
  }
}

import { useEffect, useRef, useState } from 'react';

type Job = { _id: string; status: 'queued'|'running'|'done'|'failed'; processedRows?: number; downloadUrl?: string; error?: string };

export function useExport() {
  const [job, setJob] = useState<Job | null>(null);
  const pollRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const start = async (filters: unknown) => {
    const res = await fetch('/api/exports', { method: 'POST', credentials: 'include', headers: { 'content-type': 'application/json' }, body: JSON.stringify({ filters }) });
    const { jobId } = await res.json() as { jobId: string };
    setJob({ _id: jobId, status: 'queued' });
    pollRef.current = setInterval(async () => {
      const r = await fetch(`/api/exports/${jobId}`, { credentials: 'include' });
      const j = await r.json() as Job;
      setJob(j);
      if (j.status === 'done' || j.status === 'failed') { if (pollRef.current) clearInterval(pollRef.current); }
    }, 2000);
  };

  useEffect(() => () => { if (pollRef.current) clearInterval(pollRef.current); }, []);
  return { job, start };
}

import { useExport } from './useExport';

export function ExportButton() {
  const { job, start } = useExport();
  return (
    <div>
      <button onClick={() => start({})} disabled={job?.status === 'queued' || job?.status === 'running'} className="px-3 py-1 bg-black text-white rounded">Export</button>
      {job?.status === 'running' && <span className="ml-2 text-sm">Processed {job.processedRows ?? 0} rows...</span>}
      {job?.status === 'done' && job.downloadUrl && <a href={job.downloadUrl} className="ml-2 text-blue-600">Download</a>}
      {job?.status === 'failed' && <span className="ml-2 text-red-600">{job.error}</span>}
    </div>
  );
}

type Commit = { sha: string; author: string; message: string; ts: string; branch: string };
export function CommitLog({ commits }: { commits: Commit[] }) {
  return <ul>{commits.map(c => <li key={c.sha}>{c.sha.slice(0,7)} - {c.message}</li>)}</ul>;
}

import { Canvas, useThree, ThreeEvent } from '@react-three/fiber';
import { OrbitControls } from '@react-three/drei';
import { Suspense, useLayoutEffect, useMemo, useRef, useState } from 'react';
import * as THREE from 'three';

type Commit = { sha: string; author: string; message: string; ts: number; branch: string };

function stableHash(s: string): number {
  let h = 0;
  for (let i = 0; i < s.length; i++) h = (h * 31 + s.charCodeAt(i)) | 0;
  return Math.abs(h);
}

function Spheres({ commits, onPick }: { commits: Commit[]; onPick: (c: Commit) => void }) {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const positions = useMemo(() => {
    const minTs = commits.length ? Math.min(...commits.map(c => c.ts)) : 0;
    const maxTs = commits.length ? Math.max(...commits.map(c => c.ts)) : 1;
    return commits.map((c) => ({ x: ((c.ts - minTs) / (maxTs - minTs)) * 100 - 50, y: (stableHash(c.branch) % 20) - 10, z: 0 }));
  }, [commits]);

  useLayoutEffect(() => {
    const mesh = meshRef.current; if (!mesh) return;
    const m = new THREE.Matrix4();
    const c = new THREE.Color();
    commits.forEach((cm, i) => {
      const p = positions[i];
      m.setPosition(p.x, p.y, p.z);
      mesh.setMatrixAt(i, m);
      const hue = (stableHash(cm.author) % 360) / 360;
      mesh.setColorAt(i, c.setHSL(hue, 0.7, 0.55));
    });
    mesh.instanceMatrix.needsUpdate = true;
    if (mesh.instanceColor) mesh.instanceColor.needsUpdate = true;
    mesh.count = commits.length;
  }, [commits, positions]);

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, 35000]} onClick={(e: ThreeEvent<MouseEvent>) => { if (e.instanceId !== undefined) onPick(commits[e.instanceId]); }}>
      <sphereGeometry args={[0.18, 12, 8]} />
      <meshStandardMaterial />
    </instancedMesh>
  );
}

export function Timeline3D({ commits }: { commits: Commit[] }) {
  const [picked, setPicked] = useState<Commit | null>(null);
  return (
    <div className="flex h-screen">
      <div className="flex-1 bg-slate-900">
        <Canvas camera={{ position: [0, 0, 30], fov: 50 }} dpr={[1, 2]}>
          <ambientLight intensity={0.6} />
          <directionalLight position={[10, 10, 10]} intensity={0.7} />
          <Suspense fallback={null}><Spheres commits={commits} onPick={setPicked} /></Suspense>
          <OrbitControls />
        </Canvas>
      </div>
      <aside className="w-80 p-4 bg-white overflow-auto">
        {picked ? (
          <>
