import { Request, Response, NextFunction } from 'express';
import crypto from 'node:crypto';
import { InviteModel } from '../models/invite.model';
import { redis } from '../infra/redis';
import { enqueue } from '../queue/enqueue';
import { HttpError } from '../errors/http-error';
import { auditLog } from '../services/audit.service';

const THROTTLE_KEY = (email: string) => `invite-throttle:${email.toLowerCase()}`;
const THROTTLE_LIMIT = 3;
const THROTTLE_WINDOW = 24 * 60 * 60;

function hashToken(t: string) { return crypto.createHash('sha256').update(t).digest('hex'); }

export const sendInvite = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { email, orgId } = req.body as { email: string; orgId: string };
    const tEmail = email.toLowerCase();
    const count = await redis.incr(THROTTLE_KEY(tEmail));
    if (count === 1) await redis.expire(THROTTLE_KEY(tEmail), THROTTLE_WINDOW);
    if (count > THROTTLE_LIMIT) throw new HttpError(429, 'INVITE_RATE_LIMIT');
    const token = crypto.randomBytes(32).toString('base64url');
    await InviteModel.create({ orgId, email: tEmail, tokenHash: hashToken(token), invitedBy: req.user!.id, expiresAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000) });
    await enqueue.email({ to: tEmail, template: 'invite', data: { url: `https://app.example.com/join#${token}` } });
    await auditLog({ actorId: req.user!.id, action: 'invite.sent', target: tEmail, orgId });
    res.json({ ok: true });
  } catch (err) { next(err); }
};

export const acceptInvite = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { token } = req.body as { token: string };
    const invite = await InviteModel.findOne({ tokenHash: hashToken(token) });
    if (!invite) throw new HttpError(404, 'INVALID_TOKEN');
    if (invite.status !== 'pending') throw new HttpError(409, 'ALREADY_PROCESSED');
    if (invite.expiresAt.getTime() < Date.now()) { invite.status = 'expired'; await invite.save(); throw new HttpError(410, 'EXPIRED'); }
    invite.status = 'accepted'; invite.acceptedAt = new Date(); await invite.save();
    await auditLog({ action: 'invite.accepted', target: invite.email, orgId: invite.orgId.toString() });
    res.json({ orgId: invite.orgId, email: invite.email });
  } catch (err) { next(err); }
};

import { useEffect, useState } from 'react';

export function AcceptInvite() {
  const [status, setStatus] = useState<'loading'|'ok'|'error'>('loading');
  const [orgId, setOrgId] = useState<string | null>(null);

  useEffect(() => {
    const token = window.location.hash.slice(1);
