    fetch('/api/invites/accept', { method: 'POST', credentials: 'include', headers: { 'content-type': 'application/json' }, body: JSON.stringify({ token }) })
      .then(r => r.json().then(b => ({ ok: r.ok, b })))
      .then(({ ok, b }) => { if (ok) { setOrgId(b.orgId); setStatus('ok'); } else setStatus('error'); })
      .catch(() => setStatus('error'));
  }, []);

  if (status === 'loading') return <div>Processing invite...</div>;
  if (status === 'error') return <div className="text-red-600">This invite is invalid or expired.</div>;
  return <div>Joined org {orgId}. <a href="/">Continue</a></div>;
}

