import { Server } from 'socket.io';
import { messageBus } from '../events/message.bus';

const SHARDS = 32;
function shardFor(userId: string): number { let h = 0; for (const c of userId) h = (h * 31 + c.charCodeAt(0)) | 0; return Math.abs(h) % SHARDS; }

let batch: { _id: string; title: string }[] = [];
let batchTimer: ReturnType<typeof setTimeout> | null = null;

export function attachFeedNamespace(io: Server) {
  const ns = io.of('/feed');
  ns.on('connection', (socket) => {
    const userId = (socket as any).data.userId as string;
    socket.join(`feed-shard:${shardFor(userId)}`);
  });
  messageBus.on('post.created' as never, (post: { _id: string; title: string; critical?: boolean }) => {
    if (post.critical) {
      void emitToAllShards(ns, 'post:new', post);
      return;
    }
    batch.push(post);
    if (!batchTimer) {
      batchTimer = setTimeout(async () => {
        const items = batch; batch = []; batchTimer = null;
        await emitToAllShards(ns, 'post:batch', items);
      }, 1000);
    }
  });
}

async function emitToAllShards(ns: any, event: string, payload: unknown) {
  for (let s = 0; s < SHARDS; s++) {
    ns.to(`feed-shard:${s}`).emit(event, payload);
    // micro-pause to prevent event-loop monopoly across nodes
    if (s % 8 === 7) await new Promise(r => setImmediate(r));
  }
}

