function sign(secret: string, timestamp: number, body: string): string {
  return 'sha256=' + crypto.createHmac('sha256', secret).update(`${timestamp}.${body}`).digest('hex');
}

export async function deliver(subscription: { url: string; secret: string; secondarySecret?: string }, eventId: string, eventType: string, payload: unknown): Promise<{ ok: boolean; status: number }> {
  const body = JSON.stringify(payload);
  const timestamp = Math.floor(Date.now() / 1000);
  const sigs = [sign(subscription.secret, timestamp, body)];
  if (subscription.secondarySecret) sigs.push(sign(subscription.secondarySecret, timestamp, body));
  const res = await fetch(subscription.url, {
    method: 'POST',
    body,
    headers: {
      'content-type': 'application/json',
      'x-event-id': eventId,
      'x-event-type': eventType,
      'x-timestamp': String(timestamp),
      'x-signature': sigs.join(',')
    }
  });
  return { ok: res.ok, status: res.status };
}

// Customer verification example
const crypto = require('crypto');

function verifyWebhook(req, secret) {
  const timestamp = req.headers['x-timestamp'];
  const signatures = (req.headers['x-signature'] || '').split(',');
  if (Math.abs(Date.now() / 1000 - Number(timestamp)) > 300) throw new Error('STALE');
  const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(`${timestamp}.${req.rawBody}`).digest('hex');
  for (const sig of signatures) {
    if (sig.length === expected.length && crypto.timingSafeEqual(Buffer.from(sig), Buffer.from(expected))) return true;
  }
  throw new Error('INVALID_SIGNATURE');
}

module.exports = { verifyWebhook };

import { WebhookModel } from '../models/webhook.model';
import { deliver } from '../services/webhook.service';
import { WebhookDeliveryModel } from '../models/webhook-delivery.model';

export async function processWebhookDelivery(data: { subscriptionId: string; eventId: string; eventType: string; payload: unknown }) {
  const sub = await WebhookModel.findById(data.subscriptionId);
  if (!sub) return;
  const start = new Date();
  let status = 0; let ok = false; let error: string | null = null;
  try { const r = await deliver(sub, data.eventId, data.eventType, data.payload); status = r.status; ok = r.ok; }
  catch (e) { error = (e as Error).message; }
  await WebhookDeliveryModel.create({ subscriptionId: sub._id, eventId: data.eventId, eventType: data.eventType, status, ok, error, attemptedAt: start });
  if (!ok && (error || (status >= 500 || status === 429))) throw new Error('RETRY');
}

