import crypto from '../lib/crypto-shim';

export type Toast = { id: string; key?: string; title?: string; message: string; variant: 'info'|'success'|'warning'|'error'; durationMs: number };
type Listener = (toasts: Toast[]) => void;

let toasts: Toast[] = [];
const listeners = new Set<Listener>();
const timers = new Map<string, ReturnType<typeof setTimeout>>();

function emit() { for (const l of listeners) l(toasts); }

export const toaster = {
  subscribe(l: Listener) { listeners.add(l); l(toasts); return () => { listeners.delete(l); }; },
  show(input: Omit<Toast, 'id'> & { id?: string }): string {
    if (input.key) {
      const existing = toasts.find(t => t.key === input.key);
      if (existing) { this.dismiss(existing.id); }
    }
    const id = input.id ?? crypto.randomId();
    const next: Toast = { id, key: input.key, title: input.title, message: input.message, variant: input.variant, durationMs: input.durationMs };
    toasts = [...toasts, next];
    emit();
    if (next.durationMs > 0) {
      timers.set(id, setTimeout(() => this.dismiss(id), next.durationMs));
    }
    return id;
  },
  dismiss(id: string) {
    const t = timers.get(id);
    if (t) { clearTimeout(t); timers.delete(id); }
    toasts = toasts.filter(t => t.id !== id);
    emit();
  }
};

export default {
  randomId(): string {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) return crypto.randomUUID();
    return Math.random().toString(36).slice(2);
  }
};

