export const list = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const limit = Math.min(50, Number(req.query.limit) || 20);
    if (req.query.before) {
      const [ts, id] = String(req.query.before).split('.');
      const items = await ActivityModel.find({
        $or: [
          { createdAt: { $lt: new Date(ts) } },
          { createdAt: new Date(ts), _id: { $lt: new Types.ObjectId(id) } }
        ]
      }).sort({ createdAt: -1, _id: -1 }).limit(limit + 1).lean();
      const hasMore = items.length > limit;
      const trimmed = items.slice(0, limit);
      const next = hasMore ? `${trimmed.at(-1)!.createdAt.toISOString()}.${trimmed.at(-1)!._id}` : null;
      res.json({ items: trimmed, nextCursor: next });
      return;
    }
    if (req.query.offset) {
      const offset = Number(req.query.offset);
      const items = await ActivityModel.find({}).sort({ createdAt: -1, _id: -1 }).skip(offset).limit(limit).lean();
      res.json({ items });
      return;
    }
    const items = await ActivityModel.find({}).sort({ createdAt: -1, _id: -1 }).limit(limit + 1).lean();
    const hasMore = items.length > limit;
    const trimmed = items.slice(0, limit);
    const next = hasMore ? `${trimmed.at(-1)!.createdAt.toISOString()}.${trimmed.at(-1)!._id}` : null;
    res.json({ items: trimmed, nextCursor: next });
  } catch (err) { next(err); }
};

