type Item = { _id: string; createdAt: string; text: string };

export function useActivity(token: string) {
  const [items, setItems] = useState<Item[]>([]);
  const [cursor, setCursor] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const loadMore = useCallback(async () => {
    if (loading || cursor === undefined) return;
    setLoading(true);
    const params = cursor ? `?before=${cursor}` : '';
    const r = await fetch(`/api/activity${params}`, { credentials: 'include' }).then(r => r.json()) as { items: Item[]; nextCursor: string | null };
    setItems(prev => [...prev, ...r.items]);
    setCursor(r.nextCursor);
    setLoading(false);
  }, [cursor, loading]);

  useEffect(() => { loadMore(); }, []);

  useEffect(() => {
    const socket = io('/activity', { auth: { token } });
    socket.on('activity:new', (item: Item) => setItems(prev => [item, ...prev]));
    return () => { socket.disconnect(); };
  }, [token]);

  return { items, loadMore, loading, hasMore: cursor !== null };
}

