import { Canvas, useFrame } from '@react-three/fiber';
import { useEffect, useRef } from 'react';
import * as THREE from 'three';

type P = { active: boolean; x: number; y: number; vx: number; vy: number; life: number; color: THREE.Color };
const MAX = 1000;
const pool: P[] = Array.from({ length: MAX }, () => ({ active: false, x: 0, y: 0, vx: 0, vy: 0, life: 0, color: new THREE.Color() }));

export function emitBurst(originPx: { x: number; y: number }, hex: string) {
  if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) return;
  const color = new THREE.Color(hex);
  for (let i = 0; i < 60; i++) {
    const slot = pool.find(p => !p.active);
    if (!slot) break;
    slot.active = true;
    slot.x = (originPx.x / window.innerWidth) * 2 - 1;
    slot.y = -((originPx.y / window.innerHeight) * 2 - 1);
    const angle = Math.random() * Math.PI * 2;
    const speed = 0.005 + Math.random() * 0.01;
    slot.vx = Math.cos(angle) * speed;
    slot.vy = Math.sin(angle) * speed + 0.01;
    slot.life = 1;
    slot.color.copy(color);
  }
}

function Particles() {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const m = new THREE.Matrix4();
  useFrame((_state, delta) => {
    const mesh = meshRef.current; if (!mesh) return;
    let visible = 0;
    for (const p of pool) {
      if (!p.active) continue;
      p.x += p.vx;
      p.y += p.vy;
      p.vy -= 0.001;
      p.life -= delta * 0.6;
      if (p.life <= 0) { p.active = false; continue; }
      m.makeScale(p.life * 0.02, p.life * 0.02, p.life * 0.02);
      m.setPosition(p.x, p.y, 0);
      mesh.setMatrixAt(visible, m);
      mesh.setColorAt(visible, p.color);
      visible++;
    }
    mesh.count = visible;
    mesh.instanceMatrix.needsUpdate = true;
    if (mesh.instanceColor) mesh.instanceColor.needsUpdate = true;
  });
  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, MAX]}>
      <planeGeometry args={[1, 1]} />
      <meshBasicMaterial transparent opacity={0.9} />
    </instancedMesh>
  );
}

export function ParticleOverlay() {
  return (
    <div className="fixed inset-0 pointer-events-none z-50">
      <Canvas orthographic camera={{ zoom: 1, position: [0, 0, 1] }}>
        <Particles />
      </Canvas>
    </div>
  );
}

