const s3 = new S3Client({ region: process.env.AWS_REGION! });
const BUCKET = process.env.AUDIT_ARCHIVE_BUCKET!;

export async function archiveDay(day: Date) {
  const start = new Date(day); start.setUTCHours(0,0,0,0);
  const end = new Date(start); end.setUTCDate(end.getUTCDate() + 1);
  const orgs = await AuditLogModel.distinct('orgId', { at: { $gte: start, $lt: end } });
  for (const orgId of orgs) {
    const cursor = AuditLogModel.find({ orgId, at: { $gte: start, $lt: end } }).cursor();
    const chunks: string[] = ['['];
    let first = true;
    for await (const log of cursor) {
      if (!first) chunks.push(','); else first = false;
      chunks.push(JSON.stringify(log.toObject()));
    }
    chunks.push(']');
    const body = chunks.join('');
    const key = `audit/${orgId}/${start.toISOString().slice(0,10)}.json`;
    await s3.send(new PutObjectCommand({ Bucket: BUCKET, Key: key, Body: body, ContentType: 'application/json', StorageClass: 'GLACIER_IR' }));
  }
}

