import { Request, Response, NextFunction } from 'express';
import { AuditLogModel } from '../models/audit-log.model';
import { S3Client, GetObjectCommand } from '@aws-sdk/client-s3';

const s3 = new S3Client({ region: process.env.AWS_REGION! });
const BUCKET = process.env.AUDIT_ARCHIVE_BUCKET!;

export const queryAudit = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const orgId = (req as any).orgId;
    const from = new Date(req.query.from as string);
    const to = new Date(req.query.to as string);
    const hot = await AuditLogModel.find({ orgId, at: { $gte: from, $lte: to } }).sort({ at: 1 }).lean();
    const thirty = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
    if (from >= thirty) return res.json({ items: hot, source: 'hot' });
    const days: string[] = [];
    for (let d = new Date(from); d < to; d.setUTCDate(d.getUTCDate() + 1)) days.push(d.toISOString().slice(0,10));
    const archived: unknown[] = [];
    for (const day of days) {
      try {
        const obj = await s3.send(new GetObjectCommand({ Bucket: BUCKET, Key: `audit/${orgId}/${day}.json` }));
        const text = await obj.Body!.transformToString();
        archived.push(...JSON.parse(text));
      } catch { /* missing day */ }
    }
    res.json({ items: [...archived, ...hot], source: 'hybrid' });
  } catch (err) { next(err); }
};

