import { createContext, useContext, useEffect, useState, ReactNode, useCallback } from 'react';

type Theme = 'light' | 'dark' | 'system';
type Ctx = { theme: Theme; effective: 'light' | 'dark'; setTheme: (t: Theme) => void };
const ThemeContext = createContext<Ctx | null>(null);

function resolve(theme: Theme): 'light' | 'dark' {
  if (theme !== 'system') return theme;
  return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
}

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [theme, setThemeState] = useState<Theme>(() => (localStorage.getItem('theme') as Theme | null) ?? 'system');
  const [effective, setEffective] = useState<'light' | 'dark'>(() => resolve(theme));

  useEffect(() => {
    const apply = () => {
      const eff = resolve(theme);
      setEffective(eff);
      document.documentElement.classList.toggle('dark', eff === 'dark');
    };
    apply();
    if (theme === 'system') {
      const mq = window.matchMedia('(prefers-color-scheme: dark)');
      mq.addEventListener('change', apply);
      return () => mq.removeEventListener('change', apply);
    }
  }, [theme]);

  const setTheme = useCallback((t: Theme) => {
    setThemeState(t);
    if (t === 'system') localStorage.removeItem('theme');
    else localStorage.setItem('theme', t);
  }, []);

  return <ThemeContext.Provider value={{ theme, effective, setTheme }}>{children}</ThemeContext.Provider>;
}

export const useTheme = () => { const c = useContext(ThemeContext); if (!c) throw new Error('ThemeProvider missing'); return c; };

export function Card({ children }: { children: React.ReactNode }) {
