export async function buildApp() {
  const app = express();
  app.use(helmet());
  app.get('/healthz', (_req, res) => res.status(200).json({ ok: true }));
  app.get('/readyz', (_req, res) => ready ? res.json({ ready: true }) : res.status(503).json({ ready: false }));
