}

async function startCritical() {
  await mongoose.connect(process.env.MONGO_URL!);
}

async function startBackground() {
  const [{ warmupCaches }, { startJobs }] = await Promise.all([
    import('./warmup'),
    import('./jobs')
  ]);
  await Promise.all([warmupCaches(), startJobs()]);
  ready = true;
  logger.info('background init complete');
}

