import { OrderModel } from '../models/order.model';
import { pricingService } from './pricing.service';
import { inventoryService } from './inventory.service';
import { notificationService } from './notification.service';
import { startSession } from 'mongoose';

export const orderService = {
  async place(input: { userId: string; lineItems: { productId: string; quantity: number }[] }) {
    const session = await startSession();
    try {
      let order: Awaited<ReturnType<typeof OrderModel.create>> extends (infer T)[] ? T : never = null as any;
      await session.withTransaction(async () => {
        const priced = await pricingService.priceLineItems(input.lineItems);
        await inventoryService.reserve(input.lineItems, session);
        const [created] = await OrderModel.create([{ userId: input.userId, lineItems: priced.itemsPriced, total: priced.total, status: 'pending' }], { session });
        order = created;
      });
      await notificationService.orderConfirmed({ userId: input.userId, orderId: String(order._id) });
      return order;
    } finally { session.endSession(); }
  }
};

