async function jitter() { await new Promise(r => setTimeout(r, 80 + Math.random() * 80)); }

export const checkEmail = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const email = String(req.query.email ?? '').toLowerCase().trim();
    if (!email || email.length > 320) return res.json({ available: false });
    const existing = await UserModel.exists({ email });
    await jitter();
    res.json({ available: !existing });
  } catch (err) { next(err); }
};

import { useEffect, useRef, useState } from 'react';

export function useEmailCheck(email: string) {
  const [status, setStatus] = useState<'idle'|'checking'|'available'|'taken'|'offline'|'invalid'>('idle');
  const abortRef = useRef<AbortController | null>(null);
  const timer = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    if (!email) { setStatus('idle'); return; }
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) { setStatus('invalid'); return; }
    if (timer.current) clearTimeout(timer.current);
    setStatus('checking');
    abortRef.current?.abort();
    timer.current = setTimeout(async () => {
      if (!navigator.onLine) { setStatus('offline'); return; }
      const ctrl = new AbortController();
      abortRef.current = ctrl;
      try {
        const r = await fetch(`/api/auth/check-email?email=${encodeURIComponent(email)}`, { signal: ctrl.signal });
        if (!r.ok) throw new Error('http');
        const data = await r.json() as { available: boolean };
        setStatus(data.available ? 'available' : 'taken');
      } catch (e) { if ((e as Error).name !== 'AbortError') setStatus('offline'); }
    }, 300);
    return () => { if (timer.current) clearTimeout(timer.current); abortRef.current?.abort(); };
  }, [email]);

  return status;
}

import { useState } from 'react';
import { useEmailCheck } from './useEmailCheck';
import { signupApi } from '../../api/auth';

export function Signup() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const status = useEmailCheck(email);
  const [submitting, setSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);

  const submit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitting(true); setSubmitError(null);
    try { await signupApi({ email, password }); }
    catch (err) { setSubmitError((err as Error).message); }
    finally { setSubmitting(false); }
  };

  return (
    <form onSubmit={submit} className="space-y-3">
      <div>
        <input type="email" value={email} onChange={e => setEmail(e.target.value)} className="border rounded p-2 w-full" />
        {status === 'checking' && <span className="text-xs text-gray-500">Checking...</span>}
        {status === 'available' && <span className="text-xs text-green-600">Available</span>}
        {status === 'taken' && <span className="text-xs text-red-600">Already in use</span>}
        {status === 'offline' && <span className="text-xs text-amber-600">Cannot check while offline</span>}
      </div>
      <input type="password" value={password} onChange={e => setPassword(e.target.value)} className="border rounded p-2 w-full" />
      <button type="submit" disabled={submitting || status === 'taken' || status === 'invalid'} className="px-3 py-2 bg-black text-white rounded disabled:opacity-50">Sign up</button>
      {submitError && <div className="text-red-600">{submitError}</div>}
    </form>
  );
}

