import { Canvas, useThree } from '@react-three/fiber';
import { useGLTF, OrbitControls, Decal, useTexture } from '@react-three/drei';
import { Suspense, useEffect, useRef, useState } from 'react';
import * as THREE from 'three';
import { useSearchParams } from 'react-router-dom';

function Model({ url, color, decalText }: { url: string; color: string; decalText: string }) {
  const gltf = useGLTF(url);
  const meshRef = useRef<THREE.Mesh>(null);

  useEffect(() => {
    gltf.scene.traverse((obj) => {
      if ((obj as THREE.Mesh).isMesh) {
        const m = (obj as THREE.Mesh).material as THREE.MeshStandardMaterial;
        if (m && 'color' in m) m.color.set(color);
        meshRef.current = obj as THREE.Mesh;
      }
    });
  }, [gltf, color]);

  const decalTexture = useTexture(`/api/decal-text?text=${encodeURIComponent(decalText)}`);

  return (
    <>
      <primitive object={gltf.scene} />
      {meshRef.current && decalText && (
        <Decal mesh={meshRef.current as any} position={[0, 0.1, 0.5]} rotation={[0, 0, 0]} scale={0.5}>
          <meshBasicMaterial map={decalTexture} transparent />
        </Decal>
      )}
    </>
  );
}

export function Configurator({ modelUrl }: { modelUrl: string }) {
  const [params, setParams] = useSearchParams();
  const color = params.get('color') ?? '#ffffff';
  const decalText = params.get('decal') ?? '';
  const canvasRef = useRef<HTMLDivElement>(null);

  const setColor = (c: string) => { const n = new URLSearchParams(params); n.set('color', c); setParams(n, { replace: true }); };
  const setDecal = (t: string) => { const n = new URLSearchParams(params); n.set('decal', t); setParams(n, { replace: true }); };

  const exportImage = async () => {
    const canvas = canvasRef.current?.querySelector('canvas');
    if (!canvas) return;
    canvas.toBlob((blob) => {
      if (!blob) return;
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a'); a.href = url; a.download = 'configured-product.png'; a.click();
      URL.revokeObjectURL(url);
    });
  };

  return (
    <div className="flex h-screen">
      <div ref={canvasRef} className="flex-1">
        <Canvas camera={{ position: [0, 0, 3], fov: 35 }} gl={{ preserveDrawingBuffer: true }}>
          <ambientLight intensity={0.6} />
          <directionalLight position={[5, 5, 5]} intensity={0.8} />
          <Suspense fallback={null}><Model url={modelUrl} color={color} decalText={decalText} /></Suspense>
          <OrbitControls />
        </Canvas>
      </div>
      <aside className="w-72 p-4 bg-white space-y-3">
        <label className="block">Color
          <input type="color" value={color} onChange={e => setColor(e.target.value)} />
        </label>
        <label className="block">Decal text
          <input type="text" value={decalText} onChange={e => setDecal(e.target.value)} className="border rounded p-2 w-full" />
        </label>
        <button onClick={exportImage} className="px-3 py-2 bg-black text-white rounded">Save image</button>
      </aside>
    </div>
  );
}

