import { ProjectModel } from '../models/project.model';
import { GrantModel } from '../models/grant.model';
import { getTenantContext } from '../middleware/tenant-context';
import { auditLog } from '../services/audit.service';

export const projectRepo = {
  async findById(id: string) {
    const ctx = getTenantContext();
    const owned = await ProjectModel.findOne({ _id: id, orgId: ctx.orgId }).lean();
    if (owned) return { project: owned, via: 'owner' as const };
    const grant = await GrantModel.findOne({ resourceType: 'project', resourceId: id, granteeOrgId: ctx.orgId, status: 'active' }).lean();
    if (!grant) return null;
    const shared = await ProjectModel.findById(id).setOptions({ skipTenantScope: true } as any).lean();
    if (!shared) return null;
    await auditLog({ actorId: ctx.userId, action: 'project.shared-access', target: id, orgId: ctx.orgId, ownerOrgId: String(grant.ownerOrgId) });
    return { project: shared, via: 'grant' as const, scope: grant.scope };
  }
};

import { Request, Response, NextFunction } from 'express';
import { GrantModel } from '../models/grant.model';
import { HttpError } from '../errors/http-error';
import { Types } from 'mongoose';
import { auditLog } from '../services/audit.service';

export const createGrant = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const ctx = (req as any).tenantContext;
    const { resourceType, resourceId, granteeOrgId, scope } = req.body;
    const grant = await GrantModel.create({ resourceType, resourceId: new Types.ObjectId(resourceId), ownerOrgId: ctx.orgId, granteeOrgId: new Types.ObjectId(granteeOrgId), scope, createdBy: ctx.userId });
    await auditLog({ actorId: ctx.userId, action: 'grant.created', target: String(grant._id), orgId: ctx.orgId });
    res.status(201).json({ grant });
  } catch (err) { next(err); }
};

export const approveGrant = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const ctx = (req as any).tenantContext;
    if (ctx.role !== 'admin') throw new HttpError(403, 'ADMIN_REQUIRED');
    const grant = await GrantModel.findOneAndUpdate({ _id: req.params.id, granteeOrgId: ctx.orgId, status: 'pending' }, { $set: { status: 'active', approvedBy: ctx.userId, approvedAt: new Date() } }, { new: true });
    if (!grant) throw new HttpError(404, 'NOT_FOUND');
    await auditLog({ actorId: ctx.userId, action: 'grant.approved', target: String(grant._id), orgId: ctx.orgId });
    res.json({ grant });
  } catch (err) { next(err); }
};

export const revokeGrant = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const ctx = (req as any).tenantContext;
    const grant = await GrantModel.findOneAndUpdate({ _id: req.params.id, $or: [{ ownerOrgId: ctx.orgId }, { granteeOrgId: ctx.orgId }] }, { $set: { status: 'revoked' } }, { new: true });
    if (!grant) throw new HttpError(404, 'NOT_FOUND');
    await auditLog({ actorId: ctx.userId, action: 'grant.revoked', target: String(grant._id), orgId: ctx.orgId });
    res.json({ grant });
  } catch (err) { next(err); }
};

