import puppeteer, { Browser } from 'puppeteer';

const SIZE = 2;
const pool: Browser[] = [];
let idx = 0;

export async function startPdfPool() {
  for (let i = 0; i < SIZE; i++) pool.push(await puppeteer.launch({ args: ['--no-sandbox'] }));
}

export async function renderPdf(html: string): Promise<Buffer> {
  const browser = pool[idx % pool.length]; idx++;
  const page = await browser.newPage();
  try {
    await page.setContent(html, { waitUntil: 'networkidle0' });
    const pdf = await page.pdf({ format: 'A4', printBackground: true });
    return Buffer.from(pdf);
  } finally { await page.close(); }
}

export async function shutdownPdfPool() {
  for (const b of pool) await b.close();
  pool.length = 0;
}

import { renderPdf } from './pdf-pool';
import { InvoiceModel } from '../models/invoice.model';

type CacheEntry = { pdf: Buffer; expiresAt: number };
const cache = new Map<string, CacheEntry>();
const inFlight = new Map<string, Promise<Buffer>>();
const CACHE_LIMIT = 200;
const TTL_MS = 24 * 60 * 60 * 1000;

function key(invoiceId: string, version: number): string { return `${invoiceId}:${version}`; }

export async function renderInvoiceHtml(invoiceId: string): Promise<{ html: string; version: number }> {
  const inv = await InvoiceModel.findById(invoiceId);
  if (!inv) throw new Error('NOT_FOUND');
  return { html: `<html><body><h1>Invoice ${inv._id}</h1><p>Total: $${inv.total}</p></body></html>`, version: inv.version ?? 1 };
}

export async function getInvoicePdf(invoiceId: string): Promise<Buffer> {
  const { html, version } = await renderInvoiceHtml(invoiceId);
  const k = key(invoiceId, version);
  const cached = cache.get(k);
  if (cached && cached.expiresAt > Date.now()) return cached.pdf;
  const existing = inFlight.get(k);
  if (existing) return existing;
  const p = (async () => {
    try {
      const pdf = await renderPdf(html);
      cache.set(k, { pdf, expiresAt: Date.now() + TTL_MS });
      if (cache.size > CACHE_LIMIT) { const firstKey = cache.keys().next().value; cache.delete(firstKey!); }
      return pdf;
    } finally { inFlight.delete(k); }
  })();
  inFlight.set(k, p);
  return p;
}

