export type FieldConfig = { type: 'string' | 'number' | 'boolean' | 'date'; operators: Array<'$eq'|'$ne'|'$gt'|'$gte'|'$lt'|'$lte'|'$in'|'$nin'> };
export type ResourceQuerySchema = Record<string, FieldConfig>;

const ALLOWED_OPERATORS = new Set(['$eq','$ne','$gt','$gte','$lt','$lte','$in','$nin']);

export class QueryValidationError extends Error {}

function coerce(value: unknown, type: FieldConfig['type']): unknown {
  switch (type) {
    case 'string': if (typeof value !== 'string') throw new QueryValidationError('expected string'); return value;
    case 'number': { const n = typeof value === 'number' ? value : Number(value); if (!Number.isFinite(n)) throw new QueryValidationError('expected number'); return n; }
    case 'boolean': if (typeof value !== 'boolean') throw new QueryValidationError('expected boolean'); return value;
    case 'date': { const d = value instanceof Date ? value : new Date(value as string); if (isNaN(d.getTime())) throw new QueryValidationError('expected date'); return d; }
  }
}

export function buildSafeFilter(input: unknown, schema: ResourceQuerySchema): Record<string, unknown> {
  if (!input || typeof input !== 'object') throw new QueryValidationError('filter must be object');
  const out: Record<string, unknown> = {};
  for (const [field, raw] of Object.entries(input as Record<string, unknown>)) {
    const cfg = schema[field];
    if (!cfg) throw new QueryValidationError(`field not allowed: ${field}`);
    if (raw === null || typeof raw !== 'object' || raw instanceof Date) {
      out[field] = coerce(raw, cfg.type);
      continue;
    }
    const sub: Record<string, unknown> = {};
    for (const [op, val] of Object.entries(raw)) {
      if (!ALLOWED_OPERATORS.has(op)) throw new QueryValidationError(`operator not allowed: ${op}`);
      if (!cfg.operators.includes(op as any)) throw new QueryValidationError(`operator ${op} not allowed for ${field}`);
      if (op === '$in' || op === '$nin') {
        if (!Array.isArray(val)) throw new QueryValidationError(`${op} requires array`);
        if (val.length > 100) throw new QueryValidationError(`${op} too many values`);
        sub[op] = val.map(v => coerce(v, cfg.type));
      } else {
        sub[op] = coerce(val, cfg.type);
      }
    }
    out[field] = sub;
  }
  return out;
}

import { Request, Response, NextFunction } from 'express';
import { OrderModel } from '../models/order.model';
import { buildSafeFilter, QueryValidationError } from '../lib/safe-query';
import { HttpError } from '../errors/http-error';

const orderSchema = {
  status: { type: 'string' as const, operators: ['$eq','$in','$ne'] as const },
  total: { type: 'number' as const, operators: ['$eq','$gte','$lte','$gt','$lt'] as const },
  createdAt: { type: 'date' as const, operators: ['$gte','$lte','$gt','$lt'] as const }
};

export const search = async (req: Request, res: Response, next: NextFunction) => {
  try {
    let parsed: unknown = {};
    try { parsed = JSON.parse(String(req.query.filter ?? '{}')); }
    catch { throw new HttpError(400, 'INVALID_FILTER_JSON'); }
    let safe;
    try { safe = buildSafeFilter(parsed, orderSchema); }
    catch (e) { if (e instanceof QueryValidationError) throw new HttpError(400, e.message); throw e; }
    const orders = await OrderModel.find(safe).limit(50).lean();
    res.json({ orders });
  } catch (err) { next(err); }
};

import { useEffect, useState } from 'react';
import { fetchUser } from '../../api/users';

export function UserDetail({ id }: { id: string }) {
  const [user, setUser] = useState<{ name: string } | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  useEffect(() => {
    setLoading(true); setError(null);
    fetchUser(id).then(u => setUser(u)).catch(e => setError(e.message)).finally(() => setLoading(false));
  }, [id]);
  if (loading) return <div>Loading...</div>;
  if (error) return <div>{error}</div>;
  return <div>{user?.name}</div>;
}

import { useCallback, useEffect, useRef, useState } from 'react';

type AsyncState<T> =
  | { status: 'idle' }
  | { status: 'pending' }
  | { status: 'success'; data: T }
  | { status: 'error'; error: Error };

export function useAsync<T>(fn: (signal: AbortSignal) => Promise<T>, deps: unknown[]): AsyncState<T> & { refetch: () => void } {
  const [state, setState] = useState<AsyncState<T>>({ status: 'idle' });
  const abortRef = useRef<AbortController | null>(null);
  const generation = useRef(0);

  const run = useCallback(async () => {
    const gen = ++generation.current;
    abortRef.current?.abort();
    const ctrl = new AbortController();
    abortRef.current = ctrl;
    setState({ status: 'pending' });
    try {
      const data = await fn(ctrl.signal);
      if (gen === generation.current) setState({ status: 'success', data });
    } catch (e) {
      if ((e as Error).name === 'AbortError') return;
      if (gen === generation.current) setState({ status: 'error', error: e as Error });
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, deps);

  useEffect(() => { run(); return () => { abortRef.current?.abort(); }; }, [run]);
  return { ...state, refetch: run };
}

import { useAsync } from '../../lib/useAsync';
import { fetchUser } from '../../api/users';

export function UserDetail({ id }: { id: string }) {
  const state = useAsync<{ name: string }>(signal => fetchUser(id, { signal }), [id]);
  if (state.status === 'pending' || state.status === 'idle') return <div>Loading...</div>;
  if (state.status === 'error') return <div>{state.error.message} <button onClick={state.refetch}>Retry</button></div>;
  return <div>{state.data.name}</div>;
}

