import { createContext, useContext, useEffect, useState, ReactNode, useCallback } from 'react';
import IntlMessageFormat from 'intl-messageformat';

type Messages = Record<string, string>;
type Ctx = { locale: string; t: (key: string, vars?: Record<string, unknown>) => string; setLocale: (locale: string) => void };
const I18nContext = createContext<Ctx | null>(null);

const loaders: Record<string, () => Promise<{ default: Messages }>> = {
  en: () => import('./messages/en'),
  ja: () => import('./messages/ja'),
  de: () => import('./messages/de'),
  pt: () => import('./messages/pt')
};

export function I18nProvider({ initialLocale, children }: { initialLocale: string; children: ReactNode }) {
  const [locale, setLocaleState] = useState(initialLocale);
  const [messages, setMessages] = useState<Messages>({});

  useEffect(() => {
    let cancelled = false;
    (async () => {
      const loader = loaders[locale] ?? loaders.en;
      const mod = await loader();
      if (!cancelled) setMessages(mod.default);
    })();
    document.documentElement.lang = locale;
    document.documentElement.dir = ['ar','he'].includes(locale) ? 'rtl' : 'ltr';
    return () => { cancelled = true; };
  }, [locale]);

  const setLocale = useCallback((l: string) => {
    setLocaleState(l);
    try { localStorage.setItem('locale', l); } catch {}
  }, []);

  const t = useCallback((key: string, vars: Record<string, unknown> = {}) => {
    const msg = messages[key] ?? key;
    try { return new IntlMessageFormat(msg, locale).format(vars) as string; }
    catch { return msg; }
  }, [messages, locale]);

  return <I18nContext.Provider value={{ locale, t, setLocale }}>{children}</I18nContext.Provider>;
}

export const useI18n = () => { const c = useContext(I18nContext); if (!c) throw new Error('I18nProvider missing'); return c; };

import { useI18n } from '../i18n/I18nProvider';

export function CartSummary({ count, total }: { count: number; total: number }) {
  const { t } = useI18n();
  return <div>{t('cart_summary', { count, total })}</div>;
}

import { Request, Response, NextFunction } from 'express';

const SUPPORTED = ['en','ja','de','pt'];

export function detectLocale(req: Request, res: Response, next: NextFunction) {
  const accept = req.headers['accept-language'] ?? '';
  const candidates = String(accept).split(',').map(p => p.trim().split(';')[0].toLowerCase().slice(0, 2));
  const locale = candidates.find(c => SUPPORTED.includes(c)) ?? 'en';
  res.locals.locale = locale;
  next();
}
